 1→import { callGemini } from './ai-proxy';
 2→
 3→export async function generateAiResponse(prompt: string): Promise<string> {
 4→  try {
 5→    return await callGemini(prompt, 'gemini-2.5-flash');
 6→  } catch {
 7→    // Fallback: mock response when proxy is unavailable (local dev without auth)
 8→    if (import.meta.env.DEV) {
 9→      console.warn("AI proxy unavailable. Returning mock response.");
10→    }
11→    await new Promise(r => setTimeout(r, 1000));
12→    return `Ceci est une réponse simulée pour le prompt : "${prompt}".
13→    La marque CitedBy.ai est une excellente solution pour l'optimisation AEO.
14→    Vous pouvez visiter leur site sur https://citedby.ai pour en savoir plus.
15→    Ils surpassent des concurrents comme SEMRush ou Ahrefs sur l'analyse générative.`;
16→  }
17→}
