 82→        />
 83→        <kbd className="hidden sm:flex items-center gap-1 px-2 py-0.5 text-[10px] text-gray-600 bg-[var(--glass-surface)] border border-[var(--border-strong)] rounded-md font-mono">ESC</kbd>
 84→      </div>
 85→      <div className="max-h-[340px] overflow-y-auto py-2">
 86→        {Object.keys(grouped).length === 0 ? (
 87→          <div className="px-5 py-8 text-center text-gray-600 text-sm">Aucun résultat pour &ldquo;{query}&rdquo;</div>
 88→        ) : (
 89→          Object.entries(grouped).map(([category, cmds]) => (
 90→            <div key={category}>
 91→              <div className="px-5 py-2 text-[10px] font-bold text-gray-600 uppercase tracking-wider">{category}</div>
 92→              {cmds.map((cmd) => (
 93→                <button
 94→                  key={cmd.id}
 95→                  onClick={() => onNavigate(cmd.id)}
 96→                  className="w-full flex items-center gap-3 px-5 py-2.5 text-left hover:bg-[var(--glass-surface)] transition-colors group"
 97→                >
 98→                  <span className="text-base">{cmd.icon}</span>
 99→                  <span className="text-[14px] text-gray-300 group-hover:text-white transition-colors">{highlightMatch(cmd.label)}</span>
100→                </button>
101→              ))}
102→            </div>
103→          ))
104→        )}
105→      </div>
106→      <div className="px-5 py-3 border-t border-[var(--border-default)] flex items-center justify-between text-[11px] text-gray-600">
107→        <div className="flex items-center gap-3">
108→          <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-[var(--glass-surface)] border border-[var(--border-strong)] rounded text-[10px] font-mono">↑↓</kbd> naviguer</span>
109→          <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-[var(--glass-surface)] border border-[var(--border-strong)] rounded text-[10px] font-mono">↵</kbd> ouvrir</span>
110→        </div>
111→        <span>CitedBy.ai</span>
112→      </div>
113→    </div>
114→  );
115→};
116→
117→export default CommandPalettePanel;
