 93→export function getAttributionKPIs(
 94→  period: '7d' | '30d' | '90d'
 95→): AttributionKPI {
 96→  const multiplier = period === '7d' ? 1 : period === '30d' ? 4 : 12;
 97→  return {
 98→    aiVisits: randomBetween(820, 1350) * multiplier,
 99→    aiConversions: randomBetween(24, 68) * multiplier,
100→    aiTrafficShare: parseFloat((randomBetween(80, 180) / 10).toFixed(1)),
101→    aiAvgCTR: parseFloat((randomBetween(25, 72) / 10).toFixed(1)),
102→  };
