157→  const platform = detectPlatform(url);
158→
159→  if (!apiKey) {
160→    // Fallback: use local generation
161→    await new Promise(resolve => setTimeout(resolve, 1200));
162→    return { content: generateOptimizedRobotsTxt(url), platformDetected: platform.name };
163→  }
